import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Uploading Logs","description":"How to upload logs for troubleshooting.","frontmatter":{"title":"Uploading Logs","description":"How to upload logs for troubleshooting.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"players/troubleshooting/uploading-logs.md","filePath":"players/troubleshooting/uploading-logs.md","lastUpdated":1768343532000}`);var a={name:`players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Uploading Logs <a class="header-anchor" href="#h1" aria-label="Permalink to “Uploading Logs”">​</a></h1><p>When troubleshooting issues, it is often necessary to provide logs to help identify the cause of the issue.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Why Should I Upload Logs? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Why Should I Upload Logs?”">​</a></h2><p>Uploading logs allows others to help you troubleshoot your issues much quicker than simply pasting the logs into a chat or forum post. It also allows you to share your logs with others without having to copy and paste them.</p><p>Some paste sites also provide syntax highlighting for logs, which makes them easier to read, and may censor sensitive information, such as your username, or system information.</p><h2 id="crash-reports" tabindex="-1">Crash Reports <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Crash Reports”">​</a></h2><p>Crash reports are automatically generated when the game crashes. They only contain crash information and not the actual logs of the game. They are located in the <code>crash-reports</code> folder in the game directory.</p><p>For more information on crash reports, see <a href="./crash-reports">Crash Reports</a>.</p><h2 id="locating-logs" tabindex="-1">Locating Logs <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Locating Logs”">​</a></h2><p>This guide covers the official Minecraft Launcher (commonly referred to as the &quot;vanilla launcher&quot;) - for third party launchers, you should consult their documentation.</p><p>Logs are located in the <code>logs</code> folder in the game directory, the game directory can be found in the following locations depending on your operating system:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>The latest log is called <code>latest.log</code>, and previous logs use the naming pattern <code>yyyy-mm-dd_number.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Uploading Logs Online <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Uploading Logs Online”">​</a></h2><p>Logs can be uploaded to a variety of services, such as:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};